# Build a map from surah name and ayah id to text for easy reference
lookup_by_surah_id = {}
for v in quran:
    lookup_by_surah_id.setdefault(v['surah_id'], {})[v['ayah_id']] = v['ayah_text']

# Find surah_id for هود
surah_to_id = {}
for v in quran:
    surah_to_id[v['surah_name']] = v['surah_id']
surah_to_id.get('هود')
